class Solution:
    def countOfPeaks(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        n = len(nums)
        # is_peak[i] stores whether nums[i] is a peak (1) or not (0)
        is_peak = [0] * n

        # Binary Indexed Tree (Fenwick Tree) for range sum queries
        # 1-indexed, size n+1
        bit = [0] * (n + 1)

        def update_bit(idx, delta):
            # idx is 0-based index in nums
            i = idx + 1
            while i <= n:
                bit[i] += delta
                i += i & (-i)

        def query_bit(idx):
            # returns prefix sum from 0 to idx (0-based)
            i = idx + 1
            s = 0
            while i > 0:
                s += bit[i]
                i -= i & (-i)
            return s

        # Initialize is_peak array and BIT
        for i in range(1, n - 1):
            if nums[i] > nums[i-1] and nums[i] > nums[i+1]:
                is_peak[i] = 1
                update_bit(i, 1)

        ans = []

        for q in queries:
            if q[0] == 1:
                l, r = q[1], q[2]
                # Peaks can only exist strictly between l and r
                if l + 1 > r - 1:
                    ans.append(0)
                else:
                    # Sum of is_peak in range [l+1, r-1]
                    res = query_bit(r - 1) - query_bit(l)
                    ans.append(res)
            else:
                idx, val = q[1], q[2]
                if nums[idx] == val:
                    continue

                nums[idx] = val

                # Updating nums[idx] can affect peak status of idx-1, idx, idx+1
                affected_indices = [idx - 1, idx, idx + 1]
                for i in affected_indices:
                    if 0 <= i < n:
                        old_status = is_peak[i]
                        new_status = 0
                        # A peak must be strictly inside the array bounds
                        if 0 < i < n - 1:
                            if nums[i] > nums[i-1] and nums[i] > nums[i+1]:
                                new_status = 1

                        if new_status != old_status:
                            is_peak[i] = new_status
                            update_bit(i, new_status - old_status)

        return ans
