class Solution:
    def maxHeightOfTriangle(self, red: int, blue: int) -> int:
        def get_max_height(r, b):
            h = 1
            while True:
                # Calculate balls needed for height h starting with color r
                # Rows 1, 3, 5... use r -> sum of first k odd numbers = k^2
                # Rows 2, 4, 6... use b -> sum of first k even numbers = k*(k+1)
                r_needed = ((h + 1) // 2) ** 2
                b_needed = (h // 2) * ((h // 2) + 1)

                if r_needed <= r and b_needed <= b:
                    h += 1
                else:
                    return h - 1

        # Check both possible starting colors (Red or Blue)
        return max(get_max_height(red, blue), get_max_height(blue, red))
